WITH proj AS (SELECT er.id FROM entity_records er WHERE er.entity_id=(SELECT id FROM entities WHERE entity_key='projects') AND er.values_json->>'name'='מרים החשמונאית 28-30' AND er.values_json->>'client'=(SELECT id FROM users WHERE email='shelli@i-almi.co.il')::text LIMIT 1),
ins AS (
  INSERT INTO entity_records (entity_id, values_json)
  SELECT (SELECT id FROM entities WHERE entity_key='orders'), jsonb_strip_nulls('{"crm_deal_id":"27889545","order_number":"3385","painter":"צבוע אצל יצרן","drawing":{"url":"https://drive.google.com/file/d/1Y2-grhXYZwuscHrlS7x1h2b5Jj6lN44F","kind":"link"}}'::jsonb || jsonb_build_object('designer', (SELECT id FROM users WHERE email='hamada@erp.local')) || jsonb_build_object('manufacturer', (SELECT id FROM users WHERE email='hamada@erp.local')))
  FROM proj
  WHERE NOT EXISTS (SELECT 1 FROM entity_records er2 WHERE er2.entity_id=(SELECT id FROM entities WHERE entity_key='orders') AND er2.values_json->>'crm_deal_id'='27889545')
  RETURNING id
)
INSERT INTO record_links (relation_id, relation_type, source_record_id, target_record_id)
SELECT (SELECT id FROM relations WHERE relation_key='proekty' AND source_entity_id=(SELECT id FROM entities WHERE entity_key='orders') AND target_entity_id=(SELECT id FROM entities WHERE entity_key='projects')), 'many_to_one', ins.id, proj.id FROM ins, proj
ON CONFLICT DO NOTHING;

-- 6) Safety check: abort if any imported order has no project link
DO $$
DECLARE orphan int;
BEGIN
  SELECT count(*) INTO orphan FROM entity_records o
  WHERE o.entity_id=(SELECT id FROM entities WHERE entity_key='orders') AND o.values_json ? 'crm_deal_id'
    AND NOT EXISTS (SELECT 1 FROM record_links rl
      WHERE rl.relation_id=(SELECT id FROM relations WHERE relation_key='proekty' AND source_entity_id=(SELECT id FROM entities WHERE entity_key='orders') AND target_entity_id=(SELECT id FROM entities WHERE entity_key='projects')) AND rl.source_record_id=o.id);
  IF orphan > 0 THEN
    RAISE EXCEPTION 'CRM import aborted: % imported orders have no project link', orphan;
  END IF;
END $$;

